  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { PolicyRecord, PolicyRule, PolicySelector, PolicyStatus } from "./types";
  3→
  4→// --- Detail Response Types ---
  5→
  6→export type PolicyEdgeInfo = {
  7→  governing: Array<{ identity_id: string; created_at: string }>;
  8→  protects: Array<{ workspace_id: string; created_at: string }>;
  9→};
 10→
 11→export type PolicyVersionChainItem = {
 12→  id: string;
 13→  version: number;
 14→  status: string;
 15→  created_at: string;
 16→};
 17→
 18→// --- List Response Types ---
 19→
 20→export type PolicyListItem = {
 21→  id: string;
 22→  title: string;
 23→  status: string;
 24→  version: number;
 25→  rules_count: number;
 26→  human_veto_required: boolean;
 27→  created_at: string;
 28→  updated_at?: string;
 29→};
 30→
 31→// --- Pure Mapping ---
 32→
 33→const formatTimestamp = (value: Date | string): string =>
 34→  value instanceof Date ? value.toISOString() : String(value);
 35→
 36→const toPolicyListItem = (record: PolicyRecord): PolicyListItem => ({
 37→  id: record.id.id as string,
 38→  title: record.title,
 39→  status: record.status,
 40→  version: record.version,
 41→  rules_count: record.rules?.length ?? 0,
 42→  human_veto_required: record.human_veto_required ?? false,
 43→  created_at: formatTimestamp(record.created_at),
 44→  ...(record.updated_at ? { updated_at: formatTimestamp(record.updated_at) } : {}),
 45→});
 46→
 47→// --- Parameter Types ---
 48→
 49→type CreatePolicyParams = {
 50→  title: string;
 51→  description: string;
 52→  selector?: PolicySelector;
 53→  rules: PolicyRule[];
 54→  human_veto_required?: boolean;
 55→  max_ttl?: string;
 56→  createdBy: RecordId<"identity">;
 57→  workspace: RecordId<"workspace">;
 58→  version?: number;
 59→  supersedes?: RecordId<"policy">;
 60→};
 61→
 62→// --- Query Functions ---
 63→
 64→export async function loadActivePolicies(
 65→  surreal: Surreal,
 66→  identityId: RecordId<"identity">,
 67→  workspaceId: RecordId<"workspace">,
 68→): Promise<PolicyRecord[]> {
 69→  const identityResult = await surreal.query<
 70→    [Array<{ policies: PolicyRecord[] }>]
 71→  >(
 72→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 73→    { identity: identityId },
 74→  );
 75→
 76→  const workspaceResult = await surreal.query<
 77→    [Array<{ policies: PolicyRecord[] }>]
 78→  >(
 79→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 80→    { workspace: workspaceId },
 81→  );
 82→
 83→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 84→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 85→
 86→  // Deduplicate by policy ID and filter active only
 87→  const seen = new Set<string>();
 88→  const result: PolicyRecord[] = [];
 89→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 90→    const id = policy.id.id as string;
 91→    if (!seen.has(id) && policy.status === "active") {
 92→      seen.add(id);
 93→      result.push(policy);
 94→    }
 95→  }
 96→  return result;
 97→}
