116→export async function createPolicy(
117→  surreal: Surreal,
118→  params: CreatePolicyParams,
119→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
120→  const policyId = `policy-${crypto.randomUUID()}`;
121→  const policyRecord = new RecordId("policy", policyId);
122→
123→  const content: Record<string, unknown> = {
124→    title: params.title,
125→    description: params.description,
126→    version: params.version ?? 1,
127→    status: "draft",
128→    selector: params.selector ?? {},
129→    rules: params.rules,
130→    human_veto_required: params.human_veto_required ?? false,
131→    created_by: params.createdBy,
132→    workspace: params.workspace,
133→    created_at: new Date(),
134→  };
135→  if (params.max_ttl) content.max_ttl = params.max_ttl;
136→  if (params.supersedes) content.supersedes = params.supersedes;
137→
138→  await surreal.query("CREATE $policy CONTENT $content;", {
139→    policy: policyRecord,
140→    content,
141→  });
142→
143→  return { policyId, policyRecord };
144→}
