146→export async function activatePolicy(
147→  surreal: Surreal,
148→  policy: PolicyRecord,
149→  creatorId: RecordId<"identity">,
150→  workspaceId: RecordId<"workspace">,
151→): Promise<void> {
152→  const policyRecord = policy.id;
153→  const supersededRecord = policy.supersedes;
154→
155→  if (supersededRecord) {
156→    // D5: Version monotonicity check inside transaction to prevent TOCTOU race.
157→    // Two concurrent activations of drafts superseding the same policy would both
158→    // read the old version outside the transaction, both pass, and both commit —
159→    // violating the single-active-version invariant. Moving the guard into the
160→    // transaction makes the check-and-update atomic.
161→    await surreal.query(
162→      `
163→      BEGIN TRANSACTION;
164→        LET $oldVer = (SELECT VALUE version FROM $oldPolicy)[0];
165→        IF $oldVer != NONE AND $policyVersion <= $oldVer {
166→          THROW string::concat("version ", <string> $policyVersion,
167→            " must be greater than superseded version ", <string> $oldVer);
168→        };
169→        UPDATE $policy SET status = 'active', updated_at = time::now();
170→        RELATE $creator->governing->$policy SET created_at = time::now();
171→        RELATE $policy->protects->$workspace SET created_at = time::now();
172→        UPDATE $oldPolicy SET status = 'superseded', updated_at = time::now();
173→        DELETE governing WHERE out = $oldPolicy;
174→        DELETE protects WHERE in = $oldPolicy;
175→      COMMIT TRANSACTION;
176→    `,
177→      {
178→        policy: policyRecord,
179→        creator: creatorId,
180→        workspace: workspaceId,
181→        oldPolicy: supersededRecord,
182→        policyVersion: policy.version,
183→      },
184→    );
185→  } else {
186→    await surreal.query(
187→      `
188→      BEGIN TRANSACTION;
189→        UPDATE $policy SET status = 'active', updated_at = time::now();
190→        RELATE $creator->governing->$policy SET created_at = time::now();
191→        RELATE $policy->protects->$workspace SET created_at = time::now();
192→      COMMIT TRANSACTION;
193→    `,
194→      {
195→        policy: policyRecord,
196→        creator: creatorId,
197→        workspace: workspaceId,
198→      },
199→    );
200→  }
201→}
