221→// --- Detail Query Functions ---
222→
223→export async function getPolicyById(
224→  surreal: Surreal,
225→  policyId: string,
226→  workspace: RecordId<"workspace">,
227→): Promise<PolicyRecord | undefined> {
228→  const policyRecord = new RecordId("policy", policyId);
229→  const policy = await surreal.select<PolicyRecord>(policyRecord);
230→
231→  if (!policy || (policy.workspace.id as string) !== (workspace.id as string)) {
232→    return undefined;
233→  }
234→
235→  return policy;
236→}
