238→export async function getPolicyEdges(
239→  surreal: Surreal,
240→  policyId: string,
241→): Promise<PolicyEdgeInfo> {
242→  const policyRecord = new RecordId("policy", policyId);
243→
244→  const [governingRows] = await surreal.query<
245→    [Array<{ in: RecordId<"identity", string>; created_at: Date }>]
246→  >(
247→    "SELECT in, created_at FROM governing WHERE out = $policy;",
248→    { policy: policyRecord },
249→  );
250→
251→  const [protectsRows] = await surreal.query<
252→    [Array<{ out: RecordId<"workspace", string>; created_at: Date }>]
253→  >(
254→    "SELECT out, created_at FROM protects WHERE in = $policy;",
255→    { policy: policyRecord },
256→  );
257→
258→  return {
259→    governing: (governingRows ?? []).map((e) => ({
260→      identity_id: e.in.id as string,
261→      created_at: formatTimestamp(e.created_at),
262→    })),
263→    protects: (protectsRows ?? []).map((e) => ({
264→      workspace_id: e.out.id as string,
