270→export function buildVersionChainSingle(policy: PolicyRecord): PolicyVersionChainItem[] {
271→  return [{
272→    id: policy.id.id as string,
273→    version: policy.version,
274→    status: policy.status,
275→    created_at: formatTimestamp(policy.created_at),
276→  }];
277→}
278→
279→// ---------------------------------------------------------------------------
280→// Version chain resolution — single-query bulk fetch + in-memory traversal
281→// ---------------------------------------------------------------------------
282→
283→/**
284→ * Fetch all versioned policies in the workspace in one query, then walk the
285→ * supersedes chain in memory. Replaces N sequential DB round-trips with 1.
286→ */
287→async function resolveChainFromPool(
288→  surreal: Surreal,
289→  policy: PolicyRecord,
290→): Promise<PolicyRecord[]> {
291→  // Single round-trip: fetch all workspace policies that participate in any
292→  // supersedes relationship (as source or target). The LET subquery collects
293→  // IDs referenced as supersedes targets so root policies (which lack
294→  // supersedes themselves) are included in the pool.
295→  const [, pool] = await surreal.query<[unknown, PolicyRecord[]]>(
296→    `LET $targets = SELECT VALUE supersedes FROM policy WHERE workspace = $ws AND supersedes != NONE;
297→     SELECT * FROM policy WHERE workspace = $ws AND (
298→       supersedes != NONE OR id IN $targets OR id = $id
299→     ) ORDER BY version ASC;`,
300→    { ws: policy.workspace, id: policy.id },
301→  );
302→
303→  // Build lookup maps for in-memory traversal
304→  const byId = new Map<string, PolicyRecord>();
305→  const bySupersedes = new Map<string, PolicyRecord>(); // key = superseded policy id
306→  for (const p of pool) {
307→    byId.set(p.id.id as string, p);
308→    if (p.supersedes) {
309→      bySupersedes.set(p.supersedes.id as string, p);
310→    }
311→  }
312→
313→  // Ensure the starting policy is in the pool (it may lack supersedes)
314→  if (!byId.has(policy.id.id as string)) {
315→    byId.set(policy.id.id as string, policy);
316→  }
317→
318→  // Walk backward to root
319→  const chain: PolicyRecord[] = [];
320→  const seen = new Set<string>();
321→  let current: PolicyRecord | undefined = policy;
322→  const ancestors: PolicyRecord[] = [];
323→  while (current?.supersedes) {
324→    const parentId = current.supersedes.id as string;
325→    if (seen.has(parentId)) break;
326→    seen.add(parentId);
327→    const parent = byId.get(parentId);
328→    if (!parent) break;
329→    ancestors.unshift(parent);
330→    current = parent;
331→  }
332→
333→  chain.push(...ancestors);
334→  if (!seen.has(policy.id.id as string)) {
335→    seen.add(policy.id.id as string);
336→    chain.push(policy);
337→  }
338→
339→  // Walk forward to latest
340→  let latestId = policy.id.id as string;
341→  for (let i = 0; i < 50; i++) {
342→    const child = bySupersedes.get(latestId);
343→    if (!child) break;
344→    const childId = child.id.id as string;
345→    if (seen.has(childId)) break;
346→    seen.add(childId);
347→    chain.push(child);
348→    latestId = childId;
349→  }
350→
351→  chain.sort((a, b) => a.version - b.version);
352→  return chain;
353→}
354→
355→/** Build version chain formatted as PolicyVersionChainItem[]. */
356→export async function buildVersionChain(
357→  surreal: Surreal,
358→  policy: PolicyRecord,
359→): Promise<PolicyVersionChainItem[]> {
360→  const chain = await resolveChainFromPool(surreal, policy);
361→  return chain.map((v) => ({
362→    id: v.id.id as string,
363→    version: v.version,
364→    status: v.status,
365→    created_at: formatTimestamp(v.created_at),
366→  }));
367→}
368→
369→/** Build enriched version chain (includes title + rules_count). */
370→export async function getVersionChain(
371→  surreal: Surreal,
372→  policyId: string,
373→  workspace: RecordId<"workspace">,
374→): Promise<Array<PolicyVersionChainItem & { title: string; rules_count: number }> | undefined> {
375→  const policy = await getPolicyById(surreal, policyId, workspace);
376→  if (!policy) return undefined;
377→
378→  const chain = await resolveChainFromPool(surreal, policy);
379→  return chain.map((v) => ({
380→    id: v.id.id as string,
381→    version: v.version,
382→    status: v.status,
383→    created_at: formatTimestamp(v.created_at),
384→    title: v.title,
385→    rules_count: v.rules?.length ?? 0,
386→  }));
387→}
388→
389→export async function createPolicyAuditEvent(
390→  surreal: Surreal,
391→  eventType: string,
392→  actor: RecordId<"identity">,
393→  workspace: RecordId<"workspace">,
394→  policyId: string,
395→  version: number,
396→): Promise<void> {
397→  const auditId = `audit-${crypto.randomUUID()}`;
398→  const auditRecord = new RecordId("audit_event", auditId);
399→
400→  await surreal.query("CREATE $audit CONTENT $content;", {
401→    audit: auditRecord,
402→    content: {
403→      event_type: eventType,
404→      actor,
405→      workspace,
406→      payload: {
407→        policy_id: policyId,
408→        policy_version: version,
409→      },
410→      severity: "info",
411→      created_at: new Date(),
412→    },
413→  });
414→}
