export async function createPolicy(
  surreal: Surreal,
  params: CreatePolicyParams,
): Promise<{ policyId: string; policyRecord: RecordId<"policy">; version: number }> {
  const policyId = `policy-${crypto.randomUUID()}`;
  const policyRecord = new RecordId("policy", policyId);

  if (params.supersedes) {
    // Atomic version assignment: compute MAX(version)+1 inside the DB so
    // concurrent requests cannot both read the same source version and
    // create duplicate draft version numbers. The unique index on
    // (workspace, supersedes) rejects the second concurrent write.
    const [rows] = await surreal.query<[Array<{ version: number }>]>(
      `LET $maxVer = (SELECT VALUE version FROM policy
          WHERE workspace = $ws AND (id = $supersedes OR supersedes = $supersedes)
          ORDER BY version DESC LIMIT 1)[0] ?? 0;
       CREATE $policy CONTENT {
         title: $title,
         description: $description,
         version: $maxVer + 1,
         status: 'draft',
         selector: $selector,
         rules: $rules,
         human_veto_required: $humanVeto,
         created_by: $createdBy,
         workspace: $ws,
         supersedes: $supersedes,
         created_at: time::now()
       } RETURN version;`,
      {
        policy: policyRecord,
        ws: params.workspace,
        supersedes: params.supersedes,
        title: params.title,
        description: params.description,
        selector: params.selector ?? {},
        rules: params.rules,
        humanVeto: params.human_veto_required ?? false,
        createdBy: params.createdBy,
      },
    );
    const version = rows?.[0]?.version ?? 1;
    return { policyId, policyRecord, version };
  }

  // Non-versioned (first version) — no supersedes, always version 1.
  const content: Record<string, unknown> = {
    title: params.title,
    description: params.description,
    version: 1,
    status: "draft",
    selector: params.selector ?? {},
    rules: params.rules,
    human_veto_required: params.human_veto_required ?? false,
    created_by: params.createdBy,
    workspace: params.workspace,
    created_at: new Date(),
  };
  if (params.max_ttl) content.max_ttl = params.max_ttl;

  await surreal.query("CREATE $policy CONTENT $content;", {
    policy: policyRecord,
    content,
  });

  return { policyId, policyRecord, version: 1 };
}

